class CardTemplatePreviewerOrdinalTest : RobolectricTest() {

    @Test
    fun `ordinal selects correct standard card in note editor preview - Issue 14694`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "Hello"),
            Field(1, "World")
        )

        val model = getCurrentDatabaseModelCopy("Basic (and reversed card)")
        val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, model)

        val intent = Intent(Intent.ACTION_VIEW).apply {
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                bundleOf(
                    "editFields" to NoteService.getFieldsAsBundleForPreview(fields, false),
                    "did" to 1L
                )
            )
            putExtra("ordinal", 1)
        }

        val previewer = startActivityNormallyOpenCollectionWithIntent(TestCardTemplatePreviewer::class.java, intent)

        assertThat("Front is not displayed", previewer.cardContent, not(containsString("Hello")))
        assertThat("Back is displayed", previewer.cardContent, containsString("World"))
    }

    @Test
    @Config(qualifiers = "en")
    fun `ordinal selects correct cloze card in note editor preview - Issue 14694`() {
        val fields: MutableList<NoteService.NoteField?> = arrayListOf(
            Field(0, "{{c1::Hello}} {{c3::World}}"),
            Field(1, "Extra")
        )

        val model = getCurrentDatabaseModelCopy("Cloze")
        val tempModelPath = CardTemplateNotetype.saveTempModel(targetContext, model)

        val intent = Intent(Intent.ACTION_VIEW).apply {
            putExtra(CardTemplateNotetype.INTENT_MODEL_FILENAME, tempModelPath)
            putExtra(
                "noteEditorBundle",
                bundleOf(
                    "editFields" to NoteService.getFieldsAsBundleForPreview(fields, false),
                    "did" to 1L
                )
            )
            // c1 and c3 -> ordinals 0 and 2
            putExtra("ordinal", 2)
        }

        val previewer = startActivityNormallyOpenCollectionWithIntent(TestCardTemplatePreviewer::class.java, intent)

        assertThat("Hello should be visible on the c3 card", previewer.cardContent, containsString("Hello"))
        assertThat("World should be hidden on the c3 card", previewer.cardContent, not(containsString("World")))
    }

    private class Field(override val ord: Int, private val text: String) : NoteService.NoteField {
        override val fieldText: String
            get() = text
    }
